scwin.f_initSetTab = function() {
	// $c.gus.cfEnableObjects([tac_tabMain.tabs1, tac_tabMain.tabs2,tac_tabMain.tabs3]);
	tac_tabMain.setSelectedTabIndex(0);
}

//---------------------------------------------------------
// Tab Menu 선택시 처리
//---------------------------------------------------------
scwin.f_selectTabMenu = function(idx){
	tac_tabMain.setSelectedTabIndex(idx);

	if(idx==0){
		buttonTable1.visible( true);
		buttonTable2.visible( true);
        buttonTable3.visible( true);
	}else  if(idx==1){
		buttonTable1.visible( true);
		buttonTable2.visible( true);
        buttonTable3.visible( true);
	}else {
		buttonTable1.visible( false);
		buttonTable2.visible( false);
        buttonTable3.visible( false);
	}
}

//---------------------------------------------------------
//화면세팅
//---------------------------------------------------------
scwin.f_Set = function( gubun ) {

    switch ( gubun ) {

		case "INIT" : //초기화
            $c.gus.cfDisableKeyData();  // Key와 Data를 모두 disable(non-editable) 상태로 변경한다.
            $c.gus.cfDisableBtnOnly([
                btn_Copy,btn_Copy2,btn_Cancel,btn_Save,btn_Delete,btn_Update,btn_FileDownload,btn_HNoChg
                ,btn_Copy_1,btn_Copy2_1,btn_Cancel_1,btn_Save_1,btn_Delete_1,btn_Update_1,btn_FileDownload_1,btn_HNoChg_1
                ,grpBtn1,grpBtn2
                ,btn_1,btn_2,btn_4,btn_4_1,btn_5_freight,btn_6_freight,btn_8,btn_8_1
                ,btn_CntrReceive, pu_departmentChange, btn_AddCntr1, btn_AddCntr2
            ]);
            scwin.f_DisablePopUpObj();
            $c.gus.cfEnableBtnOnly([btn_Create, btn_Create_1, btn_9_freight]);
            $c.gus.cfEnableObjects([cnd_ed_hhblno, cnd_lc_autono, cnd_lc_mhno]); // 조회조건.
            $c.gus.cfDisableObjects([cnd_ed_hhmblno]);
            $c.gus.cfEnableObjects([tbl_Search]); // 조회조건.
            scwin.statusFlag = "I";
            break;

		case "RETRIEVE" :  //조회모드
            $c.gus.cfDisableKeyData();
            scwin.f_DisablePopUpObj();
            $c.gus.cfDisableBtnOnly([ 
                btn_Save,btn_Cancel
                ,btn_Save_1,btn_Cancel_1
                ,btn_CntrReceive
                ,grpBtn1,grpBtn2,grpBtn3,grpBtn4,grpBtn5
                ,btn_AddCntr1,btn_AddCntr2
            ]);
            $c.gus.cfEnableBtnOnly([
                btn_Copy,btn_Copy2,btn_Create, btn_Delete, btn_FileDownload, btn_HNoChg
                ,btn_Copy_1, btn_Copy2_1, btn_Create_1, btn_Delete_1, btn_FileDownload_1, btn_HNoChg_1
                ,btn_4,btn_4_1,btn_5_freight,btn_6_freight,btn_8,btn_8_1,btn_9_freight,pu_departmentChange
                ,grpBtn3,grpBtn4,grpBtn5
            ]);

            gr_ocContList.setGridReadOnly(true);
            gr_ocElList.setGridReadOnly(true);
            gr_selling_freight.setGridReadOnly(true);
            gr_partner_freight.setGridReadOnly(true);
            gr_buying_freight.setGridReadOnly(true);

            if (scwin.statusFlag == "C"){
                $c.gus.cfDisableBtnOnly([btn_Update,btn_Update_1]);
            }  else {
                $c.gus.cfEnableBtnOnly([btn_Update,btn_Update_1]);
            }
            $c.gus.cfEnableObjects([cnd_ed_hhblno, cnd_lc_autono, cnd_lc_mhno]); // 조회조건 활성화
            $c.gus.cfDisableObjects([cnd_ed_hhmblno]);  // 조회조건 비활성화

            $c.gus.cfEnableObjects([tbl_Search]); // 조회조건.
            scwin.statusFlag = "";     // flag null
            //Direct BL 생성시 Master BL 자동으로 생성되는 기능 때문에 Direct BL을 바꾸거나, Direct BL로 변경 불가능하도록 수정
            if (cnd_lc_autono.getValue() == "DIRECT"){
                $c.gus.cfDisableObjects([cnd_lc_autono]);
            }else {
                ds_autono.deleteRow(2);
            }
            break;

		case "CREATE" : //신규
            $c.gus.cfEnableKeyData();
            scwin.f_EnablePopUpObj();
            $c.gus.cfDisableBtnOnly([
                btn_Copy,btn_Copy2,btn_Create,btn_Update,btn_HNoChg
                ,btn_Copy_1,btn_Copy2_1,btn_Create_1,btn_Update_1,btn_HNoChg_1
                ,btn_Delete,btn_4,btn_4_1,btn_5_freight,btn_6_freight,btn_8,btn_8_1,pu_departmentChange
            ]);
            $c.gus.cfEnableBtnOnly([
                btn_Save,btn_Cancel,btn_FileDownload
                ,btn_Save_1,btn_Cancel_1,btn_Update_1,btn_FileDownload_1
                ,btn_1,btn_2_freight1,btn_2_freight2,pu_ResultdateChange1,pu_ResultdateChange2,pu_ResultdateChange3,btn_2,btn_9_freight, btn_Update,btn_FileDownload
                ,btn_CntrReceive, grpBtn1,grpBtn2,grpBtn3,grpBtn4,grpBtn5,btn_AddCntr1,btn_AddCntr2
            ]);

            gr_ocContList.setGridReadOnly(false);
            gr_ocElList.setGridReadOnly(false);
            gr_selling_freight.setGridReadOnly(false);
            gr_partner_freight.setGridReadOnly(false);
            gr_buying_freight.setGridReadOnly(false);
            $c.gus.cfEnableObjects([cnd_ed_hhblno, cnd_lc_autono]); // 조회조건 활성화
            $c.gus.cfDisableObjects([cnd_lc_mhno, cnd_ed_hhmblno, ed_hhmt]); // 조회조건 비활성화
            ds_autono.insertRow(2);
            ds_autono.setCellAllData(2, "code", "DIRECT");
            ds_autono.setCellAllData(2, "name", "Direct");

            $c.gus.cfDisableObjects([tbl_Search,ed_hhmt,ed_agent]); // 조회조건.
            $c.gus.cfEnableObjects([cnd_ed_hhblno,cnd_lc_autono]); // 조회조건.

            scwin.statusFlag = "C";
            break;

		case "UPDATE" :
            $c.gus.cfDisableBtnOnly([btn_Copy,btn_Copy2,btn_Update, btn_Create, btn_Delete,btn_HNoChg
                ,btn_Copy_1,btn_Copy2_1,btn_Update_1,btn_Create_1,btn_Delete_1,btn_HNoChg_1
                ,btn_4,btn_4_1,btn_5_freight,btn_6_freight,btn_8,btn_8_1,pu_departmentChange
            ]);
            $c.gus.cfEnableBtnOnly([
                btn_Cancel,btn_Save,btn_FileDownload
                ,btn_Cancel_1,btn_Save_1,btn_FileDownload_1
                ,grpBtn1,grpBtn2,grpBtn3,grpBtn4,grpBtn5
                ,btn_1,btn_2_freight1,btn_2_freight2,btn_2_freight3,btn_2,btn_9_freight, pu_ResultdateChange1, pu_ResultdateChange2, pu_ResultdateChange3
                ,btn_CntrReceive,btn_AddCntr1,btn_AddCntr2
            ]);
            $c.gus.cfDisableKey();
            scwin.f_EnablePopUpObj();
            gr_ocContList.setGridReadOnly(false);
            gr_ocElList.setGridReadOnly(false);
            gr_selling_freight.setGridReadOnly(false);
            gr_partner_freight.setGridReadOnly(false);
            gr_buying_freight.setGridReadOnly(false); 

            $c.gus.cfDisableObjects([tbl_Search]); // 조회조건.

            scwin.statusFlag = "U";
            break;

		case "SAVE" :
            $c.gus.cfDisableBtnOnly([
                btn_Save,btn_Delete,btn_Cancel
                ,btn_Save_1,btn_Delete_1,btn_Cancel_1
            ]);
            $c.gus.cfEnableBtnOnly([
                btn_Update,btn_Create,btn_FileDownload, btn_HNoChg
                ,btn_Update_1,btn_Create_1,btn_FileDownload_1,btn_HNoChg_1
            ]);
            scwin.f_Set("RETRIEVE");
            break;
	}

    // 하단 버튼 상단버튼과 동일하게 처리
    btn_Cancel_freight.setDisabled(btn_Cancel.getDisabled());
    btn_Update_freight.setDisabled(btn_Update.getDisabled());
    btn_Save_freight.setDisabled(btn_Save.getDisabled());
    btn_Delete_freight.setDisabled(btn_Delete.getDisabled());
}

