		ed_creadyDt.focus();
		return false;
	}

	// 날짜 범위 확인
	if (ed_hheta.getValue() != "") {
		if( !$c.gus.cfIsAfterDate(ed_hhetd.getValue(), ed_hheta.getValue()) ){
			await $c.gus.cfAlertMsg(E_MSG_CM_ERR_048, new Array("ETD", "ETA"));  //@은(는) 보다 작아야 합니다.
			scwin.f_selectTabMenu(0);
			ed_hhetd.focus();
			return false;
		}
	}

	//ETD-ETA가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없다.
	if( $c.gus.cfMonthsBetween(scwin.strCurDate.toDate(), ed_hhetd.getValue().toDate() )  > 3){
		await $c.win.alert("ETD가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없습니다.");
