//-------------------------------------------------------------------------
// 화면이동 (WebSquare) - 통합/리팩토링
//  - GAUCE: cfTabMenuUpdate + jsp querystring  → WebSquare: $c.win.openMenu
//  - 공통 파라미터(commonParam)로 중복 제거
//  - MasterBL / SR / Freight / HouseBLPrint 등 linkcheck 분기 포함
//  - 존재체크(if cnd_... ) 제거: 무조건 존재 가정
//-------------------------------------------------------------------------

//-------------------------------------------------------------------------
// 화면이동 1) f_openPgm (GAUCE 원본 변환 + 리팩토링)
//-------------------------------------------------------------------------
// $c.win.openMenu
// title : 탭/메뉴 타이틀
// path  : 이동할 화면 경로
// menuId: 메뉴ID(없으면 path로 대체 가능)
// param : 전달 파라미터 객체
//-------------------------------------------------------------------------
scwin.f_openPgm = function(name){

    if(name == "MasterBL"){
		// GAUCE: mhno == "NONE" 이면 linkcheck=5 + vslcd/vsl/vyg, 아니면 linkcheck=3 + blno/mhno
		if(cnd_lc_mhno.getValue() == "NONE"){
			$c.win.openMenu(
                "Export Master B/L(NEW)",
                "/ui/il/seaout/sobl/se_106_01_04b.xml",
                "se_106_01_04b.xml",
                {
                    linkcheck : "5",
                    kcomcd : (scwin.hd_kcomcd || ""),
                    vslcd : ed_hhvslcd.getValue(),
                    vsl : txt_hhvsl.getValue(),
                    vyg : txt_hhvyg.getValue()
                },
                {openAction: "exist"}
			);
		}else{
			$c.win.openMenu(
                "Export Master B/L(NEW)",
                "/ui/il/seaout/sobl/se_106_01_04b.xml",
                "se_106_01_04b.xml",
                {
                    linkcheck : "3",
                    kcomcd : (scwin.hd_kcomcd || ""),
                    blno : cnd_ed_hhblno.getValue(),
                    mhno : cnd_lc_mhno.getValue()
                },
                {openAction: "exist"}
			);
		}
	}else if(name == "SR"){
		$c.win.openMenu(
            "Shipping Request",
            "/ui/il/seaout/sosr/se_116_01_01b.xml",
            "se_116_01_01b.xml",
            {
                linkcheck : "1",
                kcomcd : (scwin.hd_kcomcd || ""),
                blno : cnd_ed_hhblno.getValue()
            },
            {openAction: "exist"}
		);

	}else if(name == "Partner"){
		$c.win.openMenu(
            "Partner Statement",
            "/ui/il/acc/acpar/ac_104_01_01b.xml",
            "ac_104_01_01b.xml",
            {
                kcomcd: scwin.hd_kcomcd,
                seaair: "S",
                iogb : scwin.hd_hhio,
                blno : cnd_ed_hhblno.getValue(),
                mblno : "",
                mhno : cnd_lc_mhno.getValue()
            },
            {openAction: "exist"}
        );
	}else if(name == "Invoice"){
		$c.win.openMenu(
            "Invoice",
            "/ui/il/acc/acinv/ac_101_01_01b.xml",
            "ac_101_01_01b.xml",
            {
                kcomcd : scwin.hd_kcomcd,
                seaair : "S",
                iogb : scwin.hd_hhio,
                blno : cnd_ed_hhblno.getValue(),
                mblno : "",
                mhno : cnd_lc_mhno.getValue()
            },
            {openAction: "exist"}
        );
	}else if(name == "Profit"){
		$c.win.openMenu(
            "Booking Sheet",
            "/ui/il/pfm/pfbs/pe_101_01_01b.xml",
            "pe_101_01_01b.xml",
            {
                kcomcd: scwin.hd_kcomcd,
                seaair: "S",
                iogb : scwin.hd_hhio,
                blno : cnd_ed_hhblno.getValue(),
                mblno : "",
                mhno : cnd_lc_mhno.getValue()
            },
            {openAction: "exist"}
        );
	}else if(name == "Freight"){
		$c.win.openMenu(
            "Export House B/L Freight",
            "/ui/il/seaout/sobl/se_105_01_04b.xml",
            "se_105_01_04b.xml",
            {
                linkcheck : "5",
