scwin._getCommonParam_freight = function(){
	return {
		kcomcd : (scwin.hd_kcomcd || ""),        // 법인코드
		seaair : "S",                            // sea:S, air:A
		iogb   : (scwin.hd_hhio || ""),          // out:O, in:I
		blno   : (cnd_ed_hhblno.getValue() || ""),// house blno
		mblno  : "",                             // master blno(원본: "")
		mhno   : (cnd_lc_mhno.getValue() || "")  // mhno
	};
};

//-------------------------------------------------------------------------
// 화면이동 (Freight) - GAUCE f_openPgm_freight 변환
// $c.win.openMenu
// title : 탭/메뉴 타이틀
// path  : 이동할 화면 경로
// menuId: 메뉴ID(없으면 path로 대체 가능)
// param : 전달 파라미터 객체
//-------------------------------------------------------------------------
// ※ 원본은 URL querystring으로 붙였지만,
//   WebSquare는 openMenu + param 객체로 전달(서버단에서 param을 쿼리로 받도록 되어있다면 자동 매핑)
scwin.f_openPgm_freight = function(name){

	var p = scwin._getCommonParam_freight();

	if(name == "Partner"){
		$c.win.openMenu(
            "Partner Statement",
            "/ui/il/acc/acpar/ac_104_01_01b.xml",
            "ac_104_01_01b.xml",
            p,
            {openAction: "exist"}
		);

	}else if(name == "Invoice"){
		$c.win.openMenu(
            "Invoice",
            "/ui/il/acc/acinv/ac_101_01_01b.xml",
            "ac_101_01_01b.xml",
            p,
            {openAction: "exist"}
		);

	}else if(name == "Profit"){
		$c.win.openMenu(
            "Booking Sheet",
            "/ui/il/pfm/pfbs/pe_101_01_01b.xml",
            "pe_101_01_01b.xml",
            p,
            {openAction: "exist"}
		);

	}else if(name == "HouseBLFind"){
		$c.win.openMenu(
            "House B/L Search",
            "/ui/il/seaout/sobl/se_105_01_02b.xml",
            "se_105_01_02b.xml",
            { hhio : (p.hd_hhio || "") },
            {openAction: "exist"}
		);

	}else if(name == "HouseBLHeader"){
		$c.win.openMenu(
            "Export House B/L",
            "/ui/il/seaout/sobl/se_105_01_01b.xml",
            "se_105_01_01b.xml",
            {
                linkcheck : "2",
                kcomcd    : p.kcomcd,
                blno      : p.blno,
                mhno      : p.mhno
		    },
            {openAction: "exist"}
		);

	}else if(name == "paymentINV"){
		$c.win.openMenu(
            "Payment Invoice",
            "/ui/il/acc/acpay/ac_106_01_01b.xml",
            "ac_106_01_01b.xml",
            {
                kcomcd : p.kcomcd,
                seaair : p.seaair,
                iogb   : p.iogb,
                blno   : p.blno,
                mhno   : p.mhno
            },
            {openAction: "exist"}
		);
	}
};

