	} else {
		var v = scwin._n(scwin._ds.get(ds_partner_freight, row, "chgWt")) * scwin._n(scwin._ds.get(ds_partner_freight, row, "sellUpr"));
		scwin._ds.set(ds_partner_freight, row, "sellAmtFcrc", Math.round(v * 100) / 100);
