scwin.uppper_onblur = function (e) {

    var val = this.getValue();
    // 특수공백문자 제거
    var specialSpaceRegex = /[\u00A0\u1680\u2000-\u200A\u2028\u2029\u202F\u205F\u3000\uFEFF]/g;

    val = val.replace(specialSpaceRegex, " ");

    this.setValue(val.toUpperCase());
};


